const myPromise = new Promise((resolve, reject) => {
  // 异步操作
  const success = true;
  if (success) {
    resolve('成功值');
  } else {
    reject(new Error('失败原因'));
  }
});

myPromise
  .then(result => {
    console.log(result);
    return result;
  })
  .catch(error => {
    console.error(error);
  })
  .finally(() => {
    console.log('完成');
  });
